import React, { useState } from 'react';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faBars, faXmark } from '@fortawesome/free-solid-svg-icons';
import './Navbar.css';
import { Link } from 'react-router-dom';
import { toast } from 'react-toastify';
import { APP_NAME } from '../../../shared/utility';
import { isMobile } from 'react-device-detect';

function Navbar() {
	const [nav, setNav] = useState(false);

	const openNav = () => {
		setNav(!nav);
	};

	return (
		<div className="navbar-section" style={{ height: isMobile ? '100px' : '' }}>
			<div className="navbar-title" style={{ fontSize: isMobile ? '20px' : '26px', marginLeft: isMobile ? '0' : '' }}>
				<Link to="/">{'ADPGxSOFTWARE SOLUTIONS'}</Link>
			</div>

			{/* Desktop */}
			<ul className="navbar-items" style={{ display: isMobile ? 'none' : 'flex' }}>
				<li>
					<a href="#/flowhero" className="navbar-links">
						{APP_NAME}
					</a>
				</li>
				<li>
					<a onClick={() => window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' })} style={{ cursor: 'pointer', fontSize: '18px' }}>
						{'About'}
					</a>
				</li>
			</ul>

			{/* Mobile */}
			<div className={`mobile-navbar ${nav ? 'open-nav' : ''}`}>
				<div onClick={openNav} className="mobile-navbar-close">
					<FontAwesomeIcon icon={faXmark} className="hamb-icon" />
				</div>

				<ul className="mobile-navbar-links">
					<li>
						<Link onClick={openNav} to="/">
							Home
						</Link>
					</li>

					<li>
						<a onClick={openNav} href="/#/flowhero">
							{APP_NAME}
						</a>
					</li>
				</ul>
			</div>

			{/* Hamburger Icon */}
			<div className="mobile-nav" style={{ display: isMobile ? 'block' : 'none' }}>
				<FontAwesomeIcon icon={faBars} onClick={openNav} className="hamb-icon" />
			</div>
		</div>
	);
}

export default Navbar;
